using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");
var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// Build chat client with automatic tool invocation
IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var notes = new ResearchNotes();
var search = new WebSearchTool();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(search.SearchWeb),
        AIFunctionFactory.Create(search.FetchPage),
        AIFunctionFactory.Create(notes.SaveNote),
        AIFunctionFactory.Create(notes.GetNotes),
    ]
};

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

List<ChatMessage> messages =
[
    new(ChatRole.System, """
        You are a thorough research agent. Given a topic, you investigate it by searching
        the web, reading relevant pages, and taking structured notes on key findings.

        Workflow:
        1. Search the web with several varied queries to cover the topic broadly.
        2. Fetch the most promising pages to gather detailed information.
        3. Save important facts, data points, and insights as notes.
        4. Review your notes and write a well-organized, comprehensive summary.

        Guidelines:
        - Perform at least 2–3 different searches.
        - Save notes frequently so details aren't lost between steps.
        - Structure the final summary with clear sections and headings.
        - Cite sources (URLs) where possible.
        """),
    new(ChatRole.User,
        $"Please research the following topic and provide a comprehensive summary:\n\n{topic}")
];

var response = await client.GetResponseAsync(messages, chatOptions);

Console.WriteLine($"\n{"📋 Research Summary",50}");
Console.WriteLine(new string('═', 60));
Console.WriteLine(response.Text);

// ────────────────────────────────────────────────────────────
// Tool: Research Notes
// ────────────────────────────────────────────────────────────
sealed class ResearchNotes
{
    private readonly List<(string Title, string Content)> _entries = [];

    [Description("Save a research note with a title and content. "
        + "Use this to record important findings during research.")]
    public string SaveNote(
        [Description("A short descriptive title")] string title,
        [Description("The content — facts, data, or insights")] string content)
    {
        _entries.Add((title, content));
        Console.WriteLine($"  📝 Saved note: {title}");
        return $"Saved note '{title}'. You now have {_entries.Count} note(s).";
    }

    [Description("Retrieve all saved research notes so far.")]
    public string GetNotes()
    {
        if (_entries.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _entries.Count; i++)
        {
            sb.AppendLine($"── Note {i + 1}: {_entries[i].Title} ──");
            sb.AppendLine(_entries[i].Content);
            sb.AppendLine();
        }
        return sb.ToString();
    }
}

// ────────────────────────────────────────────────────────────
// Tool: Web Search & Page Fetching
// ────────────────────────────────────────────────────────────
sealed partial class WebSearchTool
{
    private static readonly HttpClient s_http = new()
    {
        Timeout = TimeSpan.FromSeconds(20)
    };

    [Description("Search the web for a query. Returns titles, URLs, and snippets. "
        + "Set BING_API_KEY for Bing; falls back to DuckDuckGo otherwise.")]
    public async Task<string> SearchWeb(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🌐 Searching: {query}");
        try
        {
            var bingKey = Environment.GetEnvironmentVariable("BING_API_KEY");
            return !string.IsNullOrEmpty(bingKey)
                ? await SearchBingAsync(query, bingKey)
                : await SearchDdgAsync(query);
        }
        catch (Exception ex)
        {
            return $"Search error: {ex.Message}";
        }
    }

    [Description("Fetch and extract text from a web page URL. "
        + "Use this to read full articles found via SearchWeb.")]
    public async Task<string> FetchPage(
        [Description("The URL to fetch")] string url)
    {
        Console.WriteLine($"  📄 Fetching: {url}");
        try
        {
            using var req = new HttpRequestMessage(HttpMethod.Get, url);
            req.Headers.Add("User-Agent",
                "Mozilla/5.0 (compatible; ResearchAgent/1.0)");
            req.Headers.Add("Accept", "text/html,application/xhtml+xml");

            var resp = await s_http.SendAsync(req);
            resp.EnsureSuccessStatusCode();
            var html = await resp.Content.ReadAsStringAsync();
            var text = ExtractText(html);

            const int maxLen = 6000;
            if (text.Length > maxLen)
                text = text[..maxLen] + "\n\n[Content truncated]";

            return string.IsNullOrWhiteSpace(text)
                ? "Could not extract meaningful text from this page."
                : text;
        }
        catch (Exception ex)
        {
            return $"Fetch error: {ex.Message}";
        }
    }

    // ── Bing Web Search API ──────────────────────────────────

    private static async Task<string> SearchBingAsync(string query, string apiKey)
    {
        var url =
            $"https://api.bing.microsoft.com/v7.0/search?q={Uri.EscapeDataString(query)}&count=8";
        using var req = new HttpRequestMessage(HttpMethod.Get, url);
        req.Headers.Add("Ocp-Apim-Subscription-Key", apiKey);

        var resp = await s_http.SendAsync(req);
        resp.EnsureSuccessStatusCode();
        using var doc = JsonDocument.Parse(await resp.Content.ReadAsStringAsync());

        var sb = new StringBuilder();
        var i = 0;
        if (doc.RootElement.TryGetProperty("webPages", out var wp) &&
            wp.TryGetProperty("value", out var vals))
        {
            foreach (var r in vals.EnumerateArray())
            {
                sb.AppendLine($"{++i}. {r.GetProperty("name").GetString()}");
                sb.AppendLine($"   URL: {r.GetProperty("url").GetString()}");
                sb.AppendLine($"   {r.GetProperty("snippet").GetString()}");
                sb.AppendLine();
            }
        }

        return i > 0 ? sb.ToString() : "No results found.";
    }

    // ── DuckDuckGo HTML fallback ─────────────────────────────

    private static async Task<string> SearchDdgAsync(string query)
    {
        var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
        using var req = new HttpRequestMessage(HttpMethod.Get, url);
        req.Headers.Add("User-Agent",
            "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

        var resp = await s_http.SendAsync(req);
        resp.EnsureSuccessStatusCode();
        var html = await resp.Content.ReadAsStringAsync();

        var sb = new StringBuilder();
        var count = 0;

        var links = LinkPattern().Matches(html);
        var snippets = SnippetPattern().Matches(html);

        for (var i = 0; i < Math.Min(links.Count, 8); i++)
        {
            var href = WebUtility.HtmlDecode(links[i].Groups[1].Value);
            var title = StripHtml(links[i].Groups[2].Value);
            var snippet = i < snippets.Count
                ? StripHtml(snippets[i].Groups[1].Value)
                : "";

            if (href.Contains("uddg="))
            {
                var m = Regex.Match(href, @"uddg=([^&]+)");
                if (m.Success)
                    href = Uri.UnescapeDataString(m.Groups[1].Value);
            }

            sb.AppendLine($"{++count}. {title}");
            sb.AppendLine($"   URL: {href}");
            if (!string.IsNullOrWhiteSpace(snippet))
                sb.AppendLine($"   {snippet}");
            sb.AppendLine();
        }

        return count > 0
            ? sb.ToString()
            : "No results found. Try a different query.";
    }

    // ── HTML helpers ─────────────────────────────────────────

    private static string ExtractText(string html)
    {
        // Strip non-content elements
        var cleaned = Regex.Replace(html,
            @"<(script|style|nav|header|footer|aside)[^>]*>.*?</\1>",
            "", RegexOptions.Singleline | RegexOptions.IgnoreCase);

        // Block elements → newlines
        cleaned = Regex.Replace(cleaned,
            @"<(p|div|br|h[1-6]|li|tr)[^>]*\/?>", "\n",
            RegexOptions.IgnoreCase);

        // Strip remaining tags
        cleaned = Regex.Replace(cleaned, @"<[^>]+>", " ");
        cleaned = WebUtility.HtmlDecode(cleaned);

        // Normalize whitespace
        cleaned = Regex.Replace(cleaned, @"[ \t]+", " ");
        cleaned = Regex.Replace(cleaned, @"\n{3,}", "\n\n");
        return cleaned.Trim();
    }

    private static string StripHtml(string html) =>
        WebUtility.HtmlDecode(Regex.Replace(html, @"<[^>]+>", "")).Trim();

    [GeneratedRegex(
        @"<a[^>]+class=""[^""]*result__a[^""]*""[^>]+href=""([^""]+)""[^>]*>(.*?)</a>",
        RegexOptions.Singleline)]
    private static partial Regex LinkPattern();

    [GeneratedRegex(
        @"<a[^>]+class=""[^""]*result__snippet[^""]*""[^>]*>(.*?)</a>",
        RegexOptions.Singleline)]
    private static partial Regex SnippetPattern();
}

